// Helper function to generate MFA auth challenge (simulating the auth flow)
func (s *auth.Server) GenerateMFAAuthChallenge(ctx context.Context, user string, u2fStorage u2f.AuthenticationStorage) (*types.MFAAuthenticateChallenge, error) {
	// This simulates what mfaAuthChallenge does internally
	authPref, err := s.GetAuthPreference()
	if err != nil {
		return nil, err
	}

	u2fConfig, err := authPref.GetU2F()
	if err != nil {
		return nil, err
	}

	devices, err := s.GetMFADevices(ctx, user)
	if err != nil {
		return nil, err
	}

	challenge := &types.MFAAuthenticateChallenge{
		U2F: make([]*types.U2FChallenge, 0),
	}

	for _, dev := range devices {
		if dev.GetU2F() == nil {
			continue
		}

		ch, err := u2f.AuthenticateInit(ctx, u2f.AuthenticateInitParams{
			AppConfig:  *u2fConfig,
			Dev:        dev,
			Storage:    u2fStorage,
			StorageKey: user,
		})
		if err != nil {
			return nil, err
		}

		challenge.U2F = append(challenge.U2F, &types.U2FChallenge{
			KeyHandle: ch.KeyHandle,
			Challenge: ch.Challenge,
			AppID:     ch.AppID,
		})
	}

	return challenge, nil
}

