	devices, err := authServer.GetMFADevices(ctx, username)
	require.NoError(t, err, "failed to get MFA devices")
	require.Equal(t, deviceCount, len(devices),
		"Expected %d devices, got %d", deviceCount, len(devices))

	// Test the bug: U2FSignRequest should return challenges for all devices,
	// but currently only returns a challenge for the first device.
	challenge, err := authServer.U2FSignRequest(username, []byte("password123"))
	require.NoError(t, err, "failed to generate U2F sign request")
	require.NotNil(t, challenge, "expected non-nil challenge")

	// The bug: U2FSignRequest returns a single challenge (SignRequest) instead of
	// challenges for all devices. The SignRequest type can only represent one device.
	//
	// WHAT THIS TEST DEMONSTRATES:
	// 1. We registered 3 U2F devices
	// 2. U2FSignRequest returns only 1 challenge
	// 3. That challenge is for the first device only
	// 4. The client cannot access/use the other registered devices
	//
	// IMPACT:
	// Users with multiple U2F tokens registered can only authenticate with the first one.
	// If that device is lost or unavailable, they have backup devices but cannot use them
	// because the authentication flow doesn't present them with options.
	//
	// ROOT CAUSE:
	// The U2FSignRequest function is designed around the old U2F API which returns
	// a single SignRequest. The newer mfaAuthChallenge function properly handles
	// multiple devices by returning an MFAAuthenticateChallenge with repeated U2F
	// challenges, but the old API is still in use in some code paths.

	// Demonstrate the limitation of the old API
	actualKeyHandle := challenge.KeyHandle

	// Count how many of our registered devices this challenge is for
	matchCount := 0
	var matchedDevice *types.MFADevice
	for _, dev := range registeredDevices {
		u2fDev := dev.GetU2F()
		require.NotNil(t, u2fDev, "expected U2F device")
		keyHandleB64 := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(u2fDev.KeyHandle)
		if keyHandleB64 == actualKeyHandle {
			matchCount++
			matchedDevice = dev
		}
	}

	// This should be 1 (the bug), but ideally should support all 3
	require.Equal(t, 1, matchCount,
		"Expected challenge to match exactly 1 device, got %d", matchCount)
	require.NotNil(t, matchedDevice, "no device matched the challenge")

	// The challenge is for the first device (order may vary based on backend iteration)
	t.Logf("BUG CONFIRMED: U2FSignRequest returned challenge for device %q (1 of %d registered)",
		matchedDevice.GetName(), deviceCount)

	// Verify that the other devices are NOT represented in the challenge
	otherDeviceCount := 0
	for _, dev := range registeredDevices {
		if dev.GetName() != matchedDevice.GetName() {
			otherDeviceCount++
		}
	}
	require.Greater(t, otherDeviceCount, 0,
		"expected other registered devices that are not in the challenge")

	t.Logf("BUG DETAIL: %d other registered devices cannot be used because they are not in the challenge",
		otherDeviceCount)
}

// TestRegression_MultiDeviceU2FClientServerCompatibility tests the client/server
// compatibility when dealing with U2F authentication challenges with multiple devices.
//
// This test verifies limitations in the old U2F authentication API when handling
// multiple devices, and demonstrates that the newer mfaAuthChallenge API properly
// supports multiple devices.
func TestRegression_MultiDeviceU2FClientServerCompatibility(t *testing.T) {
	ctx := context.Background()
	utils.InitLoggerForTests(true)

	// Setup auth server
	backend, err := lite.NewWithConfig(ctx, lite.Config{Path: t.TempDir()})
	require.NoError(t, err, "failed to create backend")
	defer backend.Close()

	clusterName, err := services.NewClusterName(services.ClusterNameSpecV2{
		ClusterName: "test.localhost",
	})
	require.NoError(t, err, "failed to create cluster name")

	authConfig := &auth.InitConfig{
		ClusterName:            clusterName,
		Backend:                backend,
		Authority:              testauthority.New(),
		SkipPeriodicOperations: true,
	}
	authServer, err := auth.NewServer(authConfig)
	require.NoError(t, err, "failed to create auth server")
	defer authServer.Close()

	err = authServer.SetClusterName(clusterName)
	require.NoError(t, err, "failed to set cluster name")

	// Set U2F auth preference
	authPref, err := services.NewAuthPreference(services.AuthPreferenceSpecV2{
		Type: U2F,
		U2F: &types.U2F{
			AppID:  "https://localhost",
			Facets: []string{"https://localhost"},
		},
	})
	require.NoError(t, err, "failed to create auth preference")
	err = authServer.SetAuthPreference(authPref)
	require.NoError(t, err, "failed to set auth preference")

	// Create user
	username := "testuser2"
	user, err := services.NewUser(username)
	require.NoError(t, err, "failed to create user")
	err = authServer.CreateUser(ctx, user)
	require.NoError(t, err, "failed to create user in backend")

	err = authServer.UpsertPassword(username, []byte("password123"))
	require.NoError(t, err, "failed to set password")

	// Register 2 U2F devices
	var deviceKeyHandles []string
	for i := 0; i < 2; i++ {
		privKey, err := ecdsa.GenerateKey(elliptic.P256(), rand.Reader)
		require.NoError(t, err, "failed to generate key")

		pubKeyBytes, err := x509.MarshalPKIXPublicKey(&privKey.PublicKey)
		require.NoError(t, err, "failed to marshal public key")

		keyHandle := make([]byte, 32)
		_, err = rand.Read(keyHandle)
		require.NoError(t, err, "failed to read random bytes")

		device := types.NewMFADevice("device-"+string(rune('0'+i)), time.Now())
		device.Device = &types.MFADevice_U2F{
			U2F: &types.U2FDevice{
				KeyHandle: keyHandle,
				PubKey:    pubKeyBytes,
			},
		}
		err = device.CheckAndSetDefaults()
		require.NoError(t, err, "failed to check and set defaults")

		err = authServer.UpsertMFADevice(ctx, username, device)
		require.NoError(t, err, "failed to upsert device")

		u2fDev := device.GetU2F()
		require.NotNil(t, u2fDev, "expected U2F device")
		keyHandleB64 := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(u2fDev.KeyHandle)
		deviceKeyHandles = append(deviceKeyHandles, keyHandleB64)
	}

	// Get all devices
	devices, err := authServer.GetMFADevices(ctx, username)
	require.NoError(t, err, "failed to get MFA devices")
	require.Equal(t, 2, len(devices), "expected 2 devices")

	// Test 1: Old API (U2FSignRequest) - Only supports one device at a time
	challenge1, err := authServer.U2FSignRequest(username, []byte("password123"))
	require.NoError(t, err, "failed to generate first U2F sign request")
	require.NotNil(t, challenge1, "expected non-nil challenge")

	// The old API can only return one KeyHandle
	oldAPIKeyHandle := challenge1.KeyHandle
	require.NotEmpty(t, oldAPIKeyHandle, "expected non-empty key handle")

	t.Logf("Old API (U2FSignRequest): Returned challenge for device with KeyHandle: %s", oldAPIKeyHandle[:20]+"...")

	// Test 2: Verify that authentication verification properly handles the response
	// by iterating through all devices to find the matching one
	u2fDev1 := devices[0].GetU2F()
	u2fDev2 := devices[1].GetU2F()
	require.NotNil(t, u2fDev1, "expected first U2F device")
	require.NotNil(t, u2fDev2, "expected second U2F device")

	kh1 := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(u2fDev1.KeyHandle)
	kh2 := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(u2fDev2.KeyHandle)

	// The challenge should be for one of the devices
	challengeMatchCount := 0
	if kh1 == oldAPIKeyHandle {
		challengeMatchCount++
	}
	if kh2 == oldAPIKeyHandle {
		challengeMatchCount++
	}

	require.Equal(t, 1, challengeMatchCount,
		"Expected challenge to match exactly one device")

	// Summary of the compatibility issue
	t.Logf("CLIENT/SERVER COMPATIBILITY ISSUE:")
	t.Logf("  - Old API returns 1 challenge for 1 device")
	t.Logf("  - Client can only authenticate with 1 device (the one in the challenge)")
	t.Logf("  - If that device is unavailable, authentication fails even though backups exist")
	t.Logf("  - This affects any client/server pair using the old U2F API")
	t.Logf("  - The newer mfaAuthChallenge API solves this by returning all challenges")
}

